package com.evolua.social.infrastructure.persistence; import java.time.Instant; import org.springframework.data.annotation.Id; import org.springframework.data.mongodb.core.mapping.Document; @Document(collection = "posts") public class PostDocument { @Id private String id; private String userId; private String content; public String getContent() { return content; } public void setContent(String content) { this.content = content; } private String community; public String getCommunity() { return community; } public void setCommunity(String community) { this.community = community; } private String visibility; public String getVisibility() { return visibility; } public void setVisibility(String visibility) { this.visibility = visibility; } private Instant createdAt; public String getId() { return id; } public void setId(String id) { this.id = id; } public String getUserId() { return userId; } public void setUserId(String userId) { this.userId = userId; } public Instant getCreatedAt() { return createdAt; } public void setCreatedAt(Instant createdAt) { this.createdAt = createdAt; } }
